def parse_nested_parens(paren_string: str) -> List[int]:
    def max_depth(s: str) -> int:
        current_depth = 0
        max_d = 0
        for ch in s:
            if ch == '(':
                current_depth += 1
                if current_depth > max_d:
                    max_d = current_depth
            elif ch == ')':
                current_depth -= 1
        return max_d

    groups = paren_string.split()
    return [max_depth(group) for group in groups]

