def move_one_ball(arr):
    if not arr:
        return True

    n = len(arr)
    # Count the number of "descents" (places where arr[i] > arr[i+1])
    # For a rotated sorted array, there can be at most 1 descent
    # (including the wrap-around from last to first element)
    descents = 0
    for i in range(n):
