def tri(n):
    if n == 0:
        return [1]

    results = [0] * (n + 1)
    results[0] = 1
    results[1] = 3

    for i in range(2, n + 1):
        if i % 2 == 0:
            results[i] = 1 + i / 2
        else:
            # tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
            # tri(n+1) = 1 + (n+1)/2 since n is odd means n+1 is even
            results[i] = results[i - 1] + results[i - 2] + (1 + (i + 1) / 2)

    return results

