def is_nested(string):
    opening = []
    closing = []
    for i, ch in enumerate(string):
        if ch == '[':
            opening.append(i)
        else:
            closing.append(i)

    # We need at least 2 opening and 2 closing brackets
    # such that we can form a nested pattern: [ ... [ ... ] ... ]
    # i.e., opening[0] < opening[1] < closing[0] < closing[1]
    # More precisely, we need two pairs where one is inside the other.

    # Use a stack-based approach to find valid nested brackets
    # Track the positions of matched pairs and check if any nesting exists

    stack = []
    matched = []
    for i, ch in enumerate(string):
        if ch == '[':
            stack.append(i)
        else:
            if stack:
                matched.append((stack.pop(), i))

    # Check if any two matched pairs are nested
    # Pair (a, b) is nested inside (c, d) if c < a and b < d
    for i in range(len(matched)):
        for j in range(len(matched)):
            if i != j:
                a, b = matched[i]
                c, d = matched[j]
                if c < a and b < d:
                    return True
    return False

